#include "max9814.h"
#include <Arduino.h>
#define MIC_PIN 36
static int _raw=0,_peak=0;static float _db=0;static unsigned long _l=0;
void max9814_setup(){analogReadResolution(12);Serial.println("[mic] OK");}
void max9814_loop(){if(millis()-_l<50)return;_l=millis();int mn=4095,mx=0;for(int i=0;i<64;i++){int s=analogRead(MIC_PIN);if(s<mn)mn=s;if(s>mx)mx=s;}_raw=(mn+mx)/2;_peak=mx-mn;_db=20.0*log10((float)_peak/4095.0)+94.0;}
int max9814_get_raw(){return _raw;}
float max9814_get_db(){return _db;}
int max9814_get_peak(){return _peak;}
